import {
  ChangeDetectionStrategy,
  Component,
  EventEmitter,
  Output,
  computed,
  inject,
  signal,
} from "@angular/core";
import { CommonModule } from "@angular/common";
import { FormsModule } from "@angular/forms";
import { MarkdownComponent } from "../markdown/markdown.component";
import {
  AnalyzeProgressEvent,
  ProjectAnalysisService,
  ProjectMemory,
} from "../../services/project-analysis.service";
import { SettingsService } from "../../services/settings.service";
import { ChatService } from "../../services/chat.service";

interface LogLine {
  text: string;
  kind: "info" | "ok" | "err";
}

type TabName = "overview" | "architecture" | "map" | "todos";

@Component({
  selector: "app-analyze-dialog",
  standalone: true,
  imports: [CommonModule, FormsModule, MarkdownComponent],
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <div
      class="fixed inset-0 z-50 flex items-center justify-center p-4 animate-fade-in"
    >
      <div
        class="absolute inset-0 bg-slate-900/50 backdrop-blur-sm"
        (click)="onBackdrop()"
      ></div>
      <div
        class="relative w-full max-w-4xl max-h-[90vh] flex flex-col card p-5 animate-slide-up"
      >
        <div class="mb-3 flex items-center justify-between gap-3">
          <h2 class="text-lg font-semibold flex items-center gap-2">
            📁 Analyze existing project
          </h2>
          <button class="btn-ghost !px-2" type="button" (click)="close.emit()">
            ✕
          </button>
        </div>

        <!-- Path input -->
        <div class="flex flex-col gap-2 sm:flex-row sm:items-end">
          <div class="flex-1">
            <label
              class="mb-1 block text-xs font-semibold uppercase tracking-wider text-slate-500"
              >Absolute project folder path</label
            >
            <input
              class="input font-mono text-sm"
              type="text"
              [(ngModel)]="path"
              placeholder="G:\\Code Generate\\TowerDefense  (or /Users/me/proj)"
              [disabled]="running()"
              (keydown.enter)="start()"
            />
          </div>
          <label
            class="flex items-center gap-2 text-xs text-slate-500 whitespace-nowrap"
          >
            <input
              type="checkbox"
              [(ngModel)]="includeLlm"
              [disabled]="running()"
            />
            Run AI analyzer
          </label>
          @if (!running()) {
            <button
              class="btn-primary"
              type="button"
              (click)="start()"
              [disabled]="!path.trim()"
            >
              Analyze
            </button>
          } @else {
            <button class="btn-danger" type="button" (click)="cancel()">
              Stop
            </button>
          }
        </div>

        @if (errorMsg()) {
          <p class="mt-2 text-sm text-red-500">{{ errorMsg() }}</p>
        }

        <!-- Body -->
        <div class="mt-4 flex-1 min-h-0 overflow-hidden flex flex-col gap-3">
          <!-- Progress log -->
          @if (logs().length) {
            <div
              class="rounded-lg border border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-900/60 max-h-40 overflow-auto p-2 text-xs font-mono"
            >
              @for (l of logs(); track $index) {
                <div
                  [class.text-red-500]="l.kind === 'err'"
                  [class.text-emerald-500]="l.kind === 'ok'"
                  [class.text-slate-500]="l.kind === 'info'"
                >
                  {{ l.text }}
                </div>
              }
            </div>
          }

          <!-- Results -->
          @if (memory(); as mem) {
            <div class="flex items-center gap-2 text-xs">
              <span class="font-semibold">{{ mem.name }}</span>
              <span class="text-slate-500 truncate">{{ mem.root }}</span>
              <span class="ml-auto text-slate-400">
                {{ mem.scan.total_files }} files ·
                {{ formatLines(mem.scan.total_lines) }} lines ·
                {{ (mem.scan.frameworks || []).join(", ") || "no framework" }}
              </span>
            </div>

            <div
              class="flex gap-1 border-b border-slate-200 dark:border-slate-800"
            >
              @for (t of tabs; track t.id) {
                <button
                  type="button"
                  class="px-3 py-1.5 text-sm font-medium border-b-2 -mb-px"
                  [ngClass]="
                    tab() === t.id
                      ? 'border-brand-500 text-brand-600 dark:text-brand-400'
                      : 'border-transparent text-slate-500 hover:text-slate-800 dark:hover:text-slate-200'
                  "
                  (click)="tab.set(t.id)"
                >
                  {{ t.label }}
                </button>
              }
            </div>

            <div
              class="flex-1 min-h-0 overflow-auto rounded-lg border border-slate-200 dark:border-slate-800 p-4"
            >
              @if (activeMarkdown(); as md) {
                <app-markdown [source]="md" />
              } @else {
                <p class="text-sm text-slate-500">_(no content)_</p>
              }
            </div>

            <div class="flex flex-wrap items-center gap-2">
              <button
                class="btn-primary"
                type="button"
                (click)="useAsContext()"
                title="Inject this project context into the chat system prompt"
              >
                Use as chat context
              </button>
              <button
                class="btn-ghost border border-slate-200 dark:border-slate-700"
                type="button"
                (click)="askInChat()"
              >
                Open chat with summary
              </button>
              <span class="ml-auto text-[11px] text-slate-500">
                Memory saved to
                <code class="font-mono">{{ memoryDir() }}</code>
              </span>
            </div>

            @if (contextApplied()) {
              <p class="text-right text-xs text-emerald-500">
                Project context applied to chat. Open a new conversation to use
                it.
              </p>
            }
          }
        </div>
      </div>
    </div>
  `,
})
export class AnalyzeDialogComponent {
  @Output() readonly close = new EventEmitter<void>();

  private svc = inject(ProjectAnalysisService);
  private settings = inject(SettingsService);
  private chat = inject(ChatService);

  protected path = "";
  protected includeLlm = true;
  protected running = signal(false);
  protected logs = signal<LogLine[]>([]);
  protected errorMsg = signal<string | null>(null);
  protected memory = signal<ProjectMemory | null>(null);
  protected memoryDir = signal<string>("");
  protected markdown = signal<Record<string, string>>({});
  protected tab = signal<TabName>("overview");
  protected contextApplied = signal(false);

  protected tabs: { id: TabName; label: string }[] = [
    { id: "overview", label: "Overview" },
    { id: "architecture", label: "Architecture" },
    { id: "map", label: "Codebase Map" },
    { id: "todos", label: "TODO Plan" },
  ];

  protected activeMarkdown = computed(() => {
    const md = this.markdown();
    switch (this.tab()) {
      case "overview":
        return md["PROJECT_ANALYSIS.md"] || "";
      case "architecture":
        return md["ARCHITECTURE.md"] || "";
      case "map":
        return md["CODEBASE_MAP.md"] || "";
      case "todos":
        return md["TODO_PLAN.md"] || "";
    }
  });

  private abort?: AbortController;

  protected formatLines(n: number): string {
    return n.toLocaleString();
  }

  protected onBackdrop(): void {
    if (this.running()) return;
    this.close.emit();
  }

  protected cancel(): void {
    this.abort?.abort();
  }

  protected async start(): Promise<void> {
    if (!this.path.trim() || this.running()) return;
    this.running.set(true);
    this.errorMsg.set(null);
    this.logs.set([]);
    this.memory.set(null);
    this.markdown.set({});
    this.contextApplied.set(false);
    this.abort = new AbortController();

    await this.svc.analyze({
      path: this.path.trim(),
      includeLlm: this.includeLlm,
      signal: this.abort.signal,
      onEvent: (ev) => this.handle(ev),
    });
    this.running.set(false);
  }

  private handle(ev: AnalyzeProgressEvent): void {
    const push = (text: string, kind: LogLine["kind"] = "info") =>
      this.logs.update((l) => [...l, { text, kind }]);

    switch (ev.type) {
      case "start":
        push(`started — ${ev.path}`, "info");
        break;
      case "progress":
        push(ev.message || "", "info");
        break;
      case "done":
        push("analysis complete ✓", "ok");
        if (ev.memory) this.memory.set(ev.memory);
        if (ev.memory_dir) this.memoryDir.set(ev.memory_dir);
        if (ev.markdown) this.markdown.set(ev.markdown);
        break;
      case "cancelled":
        push("cancelled", "err");
        break;
      case "error":
        push(`error: ${ev.message || "unknown"}`, "err");
        this.errorMsg.set(ev.message || "Analysis failed");
        break;
    }
  }

  protected useAsContext(): void {
    const mem = this.memory();
    if (!mem) return;
    const ctx = this.buildContext(mem);
    this.settings.update({ systemPrompt: ctx });
    this.contextApplied.set(true);
  }

  protected askInChat(): void {
    const mem = this.memory();
    if (!mem) return;
    const ctx = this.buildContext(mem);
    this.settings.update({ systemPrompt: ctx });
    const conv = this.chat.newConversation();
    this.chat.rename(conv.id, `Project: ${mem.name}`);
    this.close.emit();
  }

  private buildContext(mem: ProjectMemory): string {
    const a = mem.analysis || ({} as ProjectMemory["analysis"]);
    const s = mem.scan;
    const lines: string[] = [];
    lines.push(
      `You are assisting on the existing project \`${mem.name}\` located at \`${mem.root}\`.`,
    );
    lines.push(
      "Use the project facts below as ground truth. Prefer existing files and conventions over inventing new ones.",
    );
    lines.push("");
    lines.push("## Overview");
    lines.push(a.overview || "(none)");
    lines.push("");
    lines.push("## Architecture");
    lines.push(a.architecture || "(none)");
    lines.push("");
    lines.push(`## Frameworks: ${(s.frameworks || []).join(", ") || "(none)"}`);
    lines.push(
      `## Package managers: ${(s.package_managers || []).join(", ") || "(none)"}`,
    );
    lines.push("");
    lines.push("## Folder tree (truncated)");
    lines.push("```");
    lines.push((s.tree || "").slice(0, 4000));
    lines.push("```");
    const todos = a.todos || [];
    if (todos.length) {
      lines.push("");
      lines.push("## Suggested todos");
      todos
        .slice(0, 10)
        .forEach((t) =>
          lines.push(
            `- [${t.priority || "?"}] ${t.title}${t.why ? " — " + t.why : ""}`,
          ),
        );
    }
    return lines.join("\n");
  }
}

import {
  AfterViewInit,
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  EventEmitter,
  Output,
  ViewChild,
  computed,
  inject,
  signal,
} from "@angular/core";
import { CommonModule } from "@angular/common";
import { FormsModule } from "@angular/forms";
import { ChatService } from "../../services/chat.service";
import { ChatAttachment } from "../../core/models";

export interface SendPayload {
  text: string;
  attachments: ChatAttachment[];
}

// Per-file limit. Larger files are truncated.
const MAX_FILE_BYTES = 200_000; // 200 KB per file
const MAX_TOTAL_BYTES = 600_000; // 600 KB combined
const ALLOWED_EXT = [
  "txt",
  "md",
  "markdown",
  "rst",
  "log",
  "csv",
  "tsv",
  "json",
  "yaml",
  "yml",
  "toml",
  "ini",
  "env",
  "cfg",
  "conf",
  "py",
  "ipynb",
  "js",
  "jsx",
  "ts",
  "tsx",
  "mjs",
  "cjs",
  "html",
  "htm",
  "css",
  "scss",
  "sass",
  "less",
  "java",
  "kt",
  "scala",
  "c",
  "h",
  "cpp",
  "hpp",
  "cc",
  "cs",
  "go",
  "rs",
  "rb",
  "php",
  "swift",
  "m",
  "mm",
  "sh",
  "bash",
  "zsh",
  "ps1",
  "bat",
  "cmd",
  "sql",
  "graphql",
  "proto",
  "xml",
  "svg",
  "dockerfile",
  "makefile",
  "gradle",
  "lock",
];

function isLikelyText(name: string): boolean {
  const lower = name.toLowerCase();
  if (lower === "dockerfile" || lower === "makefile" || lower === ".gitignore")
    return true;
  const ext = lower.includes(".") ? lower.split(".").pop()! : "";
  return ALLOWED_EXT.includes(ext);
}

@Component({
  selector: "app-chat-input",
  standalone: true,
  imports: [CommonModule, FormsModule],
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <form class="w-full" (submit)="onSubmit($event)">
      @if (attachments().length) {
        <div class="mb-2 flex flex-wrap gap-2">
          @for (a of attachments(); track a.name + a.size) {
            <span
              class="inline-flex items-center gap-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 px-2 py-1 text-xs"
              [title]="a.truncated ? a.name + ' (truncated)' : a.name"
            >
              <span>📎</span>
              <span class="font-mono max-w-[180px] truncate">{{ a.name }}</span>
              <span class="text-slate-400">{{ formatSize(a.size) }}</span>
              @if (a.truncated) {
                <span class="text-amber-600">trunc</span>
              }
              <button
                type="button"
                class="text-slate-400 hover:text-red-500"
                (click)="remove(a)"
                title="Remove"
              >
                ×
              </button>
            </span>
          }
        </div>
      }

      @if (error()) {
        <div
          class="mb-2 rounded-lg border border-red-300 dark:border-red-800 bg-red-50 dark:bg-red-900/20 px-3 py-1.5 text-xs text-red-600"
        >
          {{ error() }}
        </div>
      }

      <div
        class="card flex items-end gap-2 p-2 shadow-soft"
        [class.ring-2]="dragOver()"
        [class.ring-brand-500]="dragOver()"
        (dragover)="onDragOver($event)"
        (dragleave)="onDragLeave($event)"
        (drop)="onDrop($event)"
      >
        <button
          type="button"
          class="rounded-xl border px-2 py-2 text-xs font-semibold transition-colors"
          [ngClass]="
            chat.agentMode()
              ? 'border-brand-500 text-brand-600 bg-brand-50 dark:bg-brand-600/15'
              : 'border-slate-200 dark:border-slate-700 text-slate-500'
          "
          (click)="toggleAgent()"
          [title]="
            chat.agentMode()
              ? 'Agent mode ON — writes files to disk'
              : 'Agent mode OFF — chat only'
          "
        >
          {{ chat.agentMode() ? "⚡ Agent" : "💬 Chat" }}
        </button>

        <button
          type="button"
          class="rounded-xl border border-slate-200 dark:border-slate-700 px-2 py-2 text-sm text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
          (click)="picker.click()"
          title="Attach files"
          [disabled]="chat.streaming()"
        >
          📎
        </button>
        <input
          #picker
          type="file"
          multiple
          class="hidden"
          (change)="onPick($event)"
        />

        <textarea
          #ta
          class="max-h-64 min-h-[44px] flex-1 resize-none bg-transparent px-3 py-2 text-[15px] leading-relaxed focus:outline-none"
          [placeholder]="placeholder()"
          [(ngModel)]="value"
          name="prompt"
          rows="1"
          (input)="autoResize()"
          (keydown)="onKey($event)"
          [disabled]="chat.streaming()"
        ></textarea>

        @if (chat.streaming()) {
          <button
            type="button"
            class="btn-danger !rounded-xl"
            (click)="stop()"
            title="Stop generating"
          >
            ■ Stop
          </button>
        } @else {
          <button
            type="submit"
            class="btn-primary !rounded-xl"
            [disabled]="!canSend()"
            title="Send"
          >
            ↑ Send
          </button>
        }
      </div>

      <p class="mt-1 px-2 text-[11px] text-slate-400">
        Enter to send · Shift+Enter newline · Drop files to attach ·
        @if (chat.agentMode()) {
          <span class="text-brand-600 font-medium"
            >Agent mode: writes files to <code>generated_projects/</code></span
          >
        } @else {
          <span
            >Auto-detects build intent — toggle ⚡ Agent to always run the
            multi-agent pipeline</span
          >
        }
      </p>
    </form>
  `,
})
export class ChatInputComponent implements AfterViewInit {
  @ViewChild("ta") ta!: ElementRef<HTMLTextAreaElement>;
  @Output() readonly sent = new EventEmitter<SendPayload>();

  protected chat = inject(ChatService);
  protected value = "";
  protected attachments = signal<ChatAttachment[]>([]);
  protected dragOver = signal(false);
  protected error = signal<string | null>(null);

  protected canSend = computed(
    () =>
      !this.chat.streaming() &&
      (this.value.trim().length > 0 || this.attachments().length > 0),
  );

  protected placeholder = computed(() => {
    if (this.chat.streaming()) return "Generating…";
    if (this.attachments().length)
      return "Ask a question about the attached file(s)…";
    return "Ask the agent anything…";
  });

  ngAfterViewInit(): void {
    queueMicrotask(() => this.ta?.nativeElement.focus());
  }

  protected autoResize(): void {
    const el = this.ta.nativeElement;
    el.style.height = "auto";
    el.style.height = Math.min(el.scrollHeight, 256) + "px";
  }

  protected onKey(ev: KeyboardEvent): void {
    if (ev.key === "Enter" && !ev.shiftKey && !ev.isComposing) {
      ev.preventDefault();
      this.submit();
    }
  }

  protected onSubmit(ev: Event): void {
    ev.preventDefault();
    this.submit();
  }

  protected stop(): void {
    this.chat.stop();
  }
  protected toggleAgent(): void {
    this.chat.toggleAgentMode();
  }

  protected formatSize(n: number): string {
    if (n < 1024) return `${n} B`;
    if (n < 1024 * 1024) return `${(n / 1024).toFixed(1)} KB`;
    return `${(n / 1024 / 1024).toFixed(1)} MB`;
  }

  protected remove(a: ChatAttachment): void {
    this.attachments.update((list) => list.filter((x) => x !== a));
  }

  protected onDragOver(ev: DragEvent): void {
    if (ev.dataTransfer?.types?.includes("Files")) {
      ev.preventDefault();
      this.dragOver.set(true);
    }
  }
  protected onDragLeave(ev: DragEvent): void {
    ev.preventDefault();
    this.dragOver.set(false);
  }
  protected onDrop(ev: DragEvent): void {
    ev.preventDefault();
    this.dragOver.set(false);
    const files = ev.dataTransfer?.files;
    if (files && files.length) void this.addFiles(Array.from(files));
  }
  protected onPick(ev: Event): void {
    const input = ev.target as HTMLInputElement;
    if (input.files && input.files.length) {
      void this.addFiles(Array.from(input.files));
    }
    input.value = "";
  }

  private async addFiles(files: File[]): Promise<void> {
    this.error.set(null);
    const accepted: ChatAttachment[] = [];
    let totalBytes = this.attachments().reduce(
      (n, a) => n + a.content.length,
      0,
    );

    for (const f of files) {
      if (!isLikelyText(f.name)) {
        this.error.set(
          `"${f.name}" is not a recognised text file. Only source/text files are supported.`,
        );
        continue;
      }
      if (totalBytes >= MAX_TOTAL_BYTES) {
        this.error.set(
          `Total attachment size limit (${MAX_TOTAL_BYTES / 1024} KB) reached.`,
        );
        break;
      }
      try {
        let text = await f.text();
        let truncated = false;
        if (text.length > MAX_FILE_BYTES) {
          text = text.slice(0, MAX_FILE_BYTES);
          truncated = true;
        }
        const room = MAX_TOTAL_BYTES - totalBytes;
        if (text.length > room) {
          text = text.slice(0, room);
          truncated = true;
        }
        totalBytes += text.length;
        accepted.push({
          name: f.name,
          content: text,
          size: f.size,
          mime: f.type || undefined,
          truncated,
        });
      } catch (e) {
        this.error.set(`Failed to read ${f.name}: ${(e as Error).message}`);
      }
    }
    if (accepted.length) {
      this.attachments.update((list) => [...list, ...accepted]);
    }
  }

  private submit(): void {
    const text = this.value.trim();
    if (this.chat.streaming()) return;
    if (!text && this.attachments().length === 0) return;
    const payload: SendPayload = { text, attachments: this.attachments() };
    this.value = "";
    this.attachments.set([]);
    this.error.set(null);
    queueMicrotask(() => this.autoResize());
    this.sent.emit(payload);
  }
}

import { Injectable, computed, effect, inject, signal } from "@angular/core";
import {
  ChatAttachment,
  Conversation,
  ChatMessage,
  ChatStreamEvent,
} from "../core/models";
import { StreamingService } from "./streaming.service";
import { SettingsService } from "./settings.service";

const KEY = "agent_ui.conversations";
const MAX_CONVS = 200;

function uid(): string {
  if (typeof crypto !== "undefined" && "randomUUID" in crypto) {
    return (crypto as Crypto).randomUUID().replace(/-/g, "").slice(0, 16);
  }
  return Math.random().toString(36).slice(2, 12) + Date.now().toString(36);
}

@Injectable({ providedIn: "root" })
export class ChatService {
  private streamer = inject(StreamingService);
  private settings = inject(SettingsService);

  private readonly _conversations = signal<Conversation[]>(this.load());
  private readonly _activeId = signal<string | null>(null);
  private readonly _streaming = signal(false);
  private readonly _agentMode = signal<boolean>(this.loadAgentMode());
  private _abort: AbortController | null = null;

  readonly conversations = computed(() =>
    [...this._conversations()].sort((a, b) => b.updatedAt - a.updatedAt),
  );
  readonly activeId = computed(() => this._activeId());
  readonly active = computed<Conversation | null>(() => {
    const id = this._activeId();
    if (!id) return null;
    return this._conversations().find((c) => c.id === id) ?? null;
  });
  readonly streaming = computed(() => this._streaming());
  readonly agentMode = computed(() => this._agentMode());

  setAgentMode(on: boolean): void {
    this._agentMode.set(on);
    try {
      localStorage.setItem("agent_ui.agentMode", on ? "1" : "0");
    } catch {
      /* noop */
    }
  }
  toggleAgentMode(): void {
    this.setAgentMode(!this._agentMode());
  }
  private loadAgentMode(): boolean {
    try {
      return localStorage.getItem("agent_ui.agentMode") === "1";
    } catch {
      return false;
    }
  }

  constructor() {
    effect(() => {
      try {
        localStorage.setItem(KEY, JSON.stringify(this._conversations()));
      } catch {
        /* noop */
      }
    });
  }

  // ---------- conversation management ----------

  newConversation(model?: string): Conversation {
    const m = model || this.settings.settings().model || "";
    const conv: Conversation = {
      id: uid(),
      title: "New chat",
      model: m,
      messages: [],
      createdAt: Date.now(),
      updatedAt: Date.now(),
    };
    this._conversations.update((list) => [conv, ...list].slice(0, MAX_CONVS));
    this._activeId.set(conv.id);
    return conv;
  }

  select(id: string): void {
    if (this._conversations().some((c) => c.id === id)) {
      this._activeId.set(id);
    }
  }

  rename(id: string, title: string): void {
    this._conversations.update((list) =>
      list.map((c) =>
        c.id === id
          ? { ...c, title: title.trim() || c.title, updatedAt: Date.now() }
          : c,
      ),
    );
  }

  remove(id: string): void {
    this._conversations.update((list) => list.filter((c) => c.id !== id));
    if (this._activeId() === id) this._activeId.set(null);
  }

  clearAll(): void {
    this._conversations.set([]);
    this._activeId.set(null);
  }

  setModel(id: string, model: string): void {
    this._conversations.update((list) =>
      list.map((c) =>
        c.id === id ? { ...c, model, updatedAt: Date.now() } : c,
      ),
    );
  }

  // ---------- messaging ----------

  private updateConv(
    id: string,
    patch: (c: Conversation) => Conversation,
  ): void {
    this._conversations.update((list) =>
      list.map((c) => (c.id === id ? patch(c) : c)),
    );
  }

  private appendMessage(id: string, msg: ChatMessage): void {
    this.updateConv(id, (c) => ({
      ...c,
      messages: [...c.messages, msg],
      updatedAt: Date.now(),
    }));
  }

  private patchMessage(
    id: string,
    msgId: string,
    patch: Partial<ChatMessage>,
  ): void {
    this.updateConv(id, (c) => ({
      ...c,
      messages: c.messages.map((m) =>
        m.id === msgId ? { ...m, ...patch } : m,
      ),
      updatedAt: Date.now(),
    }));
  }

  /** Append text to a message efficiently (kept on a signal write). */
  private appendChunk(id: string, msgId: string, chunk: string): void {
    this.updateConv(id, (c) => ({
      ...c,
      messages: c.messages.map((m) =>
        m.id === msgId ? { ...m, content: m.content + chunk } : m,
      ),
      updatedAt: Date.now(),
    }));
  }

  /** Send a user message and stream the assistant reply. */
  async send(text: string, attachments: ChatAttachment[] = []): Promise<void> {
    const trimmed = text.trim();
    if ((!trimmed && attachments.length === 0) || this._streaming()) return;
    let conv = this.active();
    if (!conv) {
      conv = this.newConversation();
    }
    const convId = conv.id;
    const settings = this.settings.settings();
    const model = conv.model || settings.model;
    if (!model) {
      this.appendMessage(convId, {
        id: uid(),
        role: "assistant",
        content:
          "⚠️ No model selected. Pick a model in the top bar or open Settings.",
        createdAt: Date.now(),
      });
      return;
    }

    // user message
    const userMsg: ChatMessage = {
      id: uid(),
      role: "user",
      content: trimmed,
      createdAt: Date.now(),
      attachments: attachments.length ? attachments : undefined,
    };
    this.appendMessage(convId, userMsg);

    // auto-title from first user message
    if (conv.messages.length === 0 || conv.title === "New chat") {
      const titleSource = trimmed || (attachments[0]?.name ?? "New chat");
      const title =
        titleSource.slice(0, 48) + (titleSource.length > 48 ? "…" : "");
      this.updateConv(convId, (c) => ({ ...c, title, updatedAt: Date.now() }));
    }

    // assistant placeholder
    const assistantMsg: ChatMessage = {
      id: uid(),
      role: "assistant",
      content: "",
      createdAt: Date.now(),
      streaming: true,
      model,
    };
    this.appendMessage(convId, assistantMsg);

    // build history excluding the freshly added placeholder
    const history = this.active()!
      .messages.filter((m) => m.id !== assistantMsg.id)
      .map((m) => ({ ...m }));

    this._streaming.set(true);
    this._abort = new AbortController();

    await this.streamer.streamChat({
      message: userMsg.content,
      model,
      conversationId: convId,
      history: history.slice(0, -1), // exclude the user message we just sent
      attachments: userMsg.attachments,
      system: settings.systemPrompt || undefined,
      temperature: settings.temperature,
      topP: settings.topP,
      numCtx: settings.numCtx,
      maxTokens: settings.maxTokens,
      mode: this._agentMode() ? "agent" : "auto",
      outputPath: settings.outputPath || undefined,
      signal: this._abort.signal,
      onEvent: (ev: ChatStreamEvent) =>
        this.handleEvent(convId, assistantMsg.id, ev),
    });

    this.patchMessage(convId, assistantMsg.id, { streaming: false });
    this._streaming.set(false);
    this._abort = null;
  }

  private handleEvent(
    convId: string,
    msgId: string,
    ev: ChatStreamEvent,
  ): void {
    switch (ev.type) {
      case "start":
        return;
      case "chunk":
        if (ev.content) this.appendChunk(convId, msgId, ev.content);
        return;
      case "done":
        this.patchMessage(convId, msgId, { streaming: false });
        return;
      case "cancelled":
        this.patchMessage(convId, msgId, { streaming: false, cancelled: true });
        return;
      case "error":
        this.appendChunk(
          convId,
          msgId,
          `\n\n**[error]** ${ev.message ?? "unknown"}`,
        );
        this.patchMessage(convId, msgId, { streaming: false });
        return;
    }
  }

  stop(): void {
    if (this._abort) {
      this._abort.abort();
      this._abort = null;
    }
  }

  async regenerate(): Promise<void> {
    const conv = this.active();
    if (!conv || this._streaming()) return;
    const lastAssistantIdx = [...conv.messages]
      .reverse()
      .findIndex((m) => m.role === "assistant");
    if (lastAssistantIdx < 0) return;
    const realIdx = conv.messages.length - 1 - lastAssistantIdx;
    const lastUser = [...conv.messages.slice(0, realIdx)]
      .reverse()
      .find((m) => m.role === "user");
    if (!lastUser) return;
    // drop last assistant message
    this.updateConv(conv.id, (c) => ({
      ...c,
      messages: c.messages.slice(0, realIdx),
      updatedAt: Date.now(),
    }));
    await this.send(lastUser.content, lastUser.attachments ?? []);
  }

  exportConversation(id: string): string {
    const c = this._conversations().find((x) => x.id === id);
    if (!c) return "";
    return JSON.stringify(c, null, 2);
  }

  private load(): Conversation[] {
    try {
      const raw = localStorage.getItem(KEY);
      if (!raw) return [];
      const arr = JSON.parse(raw) as Conversation[];
      if (!Array.isArray(arr)) return [];
      return arr;
    } catch {
      return [];
    }
  }
}
